head.script:
let memJson = $c.data.getMemInfo();// 로그인 정보를 가져온다.
scwin.privAdmin = $c.data.getMemInfo("privAdmin");// ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님  

scwin.txtCoClsCd = ""; //ASIS hidden

scwin.MONPEROIDCREATE          = "FM06"
scwin.DATEPERIODCREATE         = "FM07"
scwin.MNGTACCTRECVCREATE       = "FM08"
scwin.ACCTRECVOVERDAYCNTCREATE = "FM09"

scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 
scwin.loginCoCd = $c.data.getMemInfo("coCd");
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.loginCoCd)?'':scwin.loginCoCd; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': scwin.loginCoClsCd;  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)

scwin.g_sCurrDate = $c.date.getServerDateTime("yyyyMMdd");

scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	/*
    f_HeaderCreate();
    rd_std[0].checked = true
    cfDisableObjects([ed_stdDt]);
    cfEnableObjects([ed_stdYm]);
    f_setCompanyInfo(); 
    ed_stdYm.Text   = g_sCurrDate.substring(0,6) 
    ed_stdDt.Text   = g_sCurrDate
    */
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    rd_std.setValue("1");
    $c.gus.cfDisableObjects([ed_stdDt]);   
    $c.gus.cfEnableObjects([ed_stdYm]);  
    ed_stdYm.setValue(scwin.g_sCurrDate.substring(0,6)); 
	ed_stdDt.setValue(scwin.g_sCurrDate);
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {

    try {
        //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
            scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
            scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
        }
        ed_coCd.setValue(scwin.vLoginCoCd);

        scwin.f_PopUpCompanyInfo('T');
    } catch (e) {
       console.log("f_setCompanyInfo: " +e);
    }
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
    /*
    var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
                                ,ed_coCd.text, txt_coNm.value
                                ,pWinCloseTF,null,null,null,null
                                ,null,null,null,null,null);
    */
    udc_coCd.setSelectId('retrieveDongbuGroupCompanyInfo');
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc // 콜백 함수
                        , ed_coCd.getValue()              // 화면에서의  Code Element의 Value
                        , ed_coNm.getValue()              // 화면에서의  Name Element의 Value
                        , pWinCloseTF                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
};

//-------------------------------------------------------------------------
// 회사코드입력시
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
    scwin.isStarted = false;
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사코드 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.isStarted = false;
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // SET	 
        if(rtnList != null ) { 
            if (rtnList[0] == "N/A") return false;  
                //if(ed_coCd.hidVal != rtnList[0] )
                ed_coCd.setValue(rtnList[0]);	// 코드
                ed_coNm.setValue(rtnList[5]);	// 회사명
                ed_coCd.hidVal = rtnList[0];  // 히든값
                scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        }else{
            ed_coCd.setValue("");	// 코드
            ed_coNm.setValue("");	// 회사명
            ed_coCd.hidVal = "";
            scwin.txtCoClsCd ="";	// 회사구분    
        }

        if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }
        if ( scwin.isStarted == true ) {
           if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
                $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
            }else {
                $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
            }
        }

    } catch (e) {
       console.log("udc_coCd_callBackFunc" + e);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    let condition = "";
    let stdDt = "";

    let ret = await $c.gus.cfValidate([ed_coCd]);
    if (!ret) {
        return false;
    }

    if( lc_createClsCd.getValue() == scwin.MONPEROIDCREATE )
	{
		stdDt = ed_stdYm.getValue().trim() + "00";
	}else if(lc_createClsCd.getValue() == scwin.DATEPERIODCREATE ){
		stdDt = ed_stdDt.getValue().trim() ;
	}else if(lc_createClsCd.getValue() == scwin.MNGTACCTRECVCREATE )
	{
		stdDt = ed_stdYm.getValue().trim() + "00";
	}else if(lc_createClsCd.getValue() == scwin.ACCTRECVOVERDAYCNTCREATE)
	{
		stdDt = ed_stdDt.getValue().trim() ;
	}
    const params = {
        closeYm     : stdDt.substring(0,6).trim() , 
        closeDd     : stdDt.substring(6,8).trim() ,
        mgntNo      : "0" ,
        coCd        : ed_coCd.getValue() ,
        wrkNo       : lc_createClsCd.getValue() ,
    };
    //데이터셋에 정보설정
    ds_acctrecvperiod_condition.setJSON(params);
    $c.sbm.execute(sbm_retrieveAcctrecvperiod);
    //sbm_retrieveAcctrecvperiod
};

//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieveAcctrecvperiod_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    if(e.responseJSON.GAUCE) {
        ds_acctrecvperiod.setJSON(e.responseJSON.GAUCE);

        if( ds_acctrecvperiod.getRowCount() == 0 ){
            tbx_totalRows.setValue(0);
            $c.win.alert(MSG_CM_WRN_002);
        }
    }
    tbx_totalRows.setValue($c.gus.cfInsertComma(ds_acctrecvperiod.getRowCount()));
};

//-------------------------------------------------------------------------
// 생성구분 정보 변경시
//-------------------------------------------------------------------------
scwin.lc_createClsCd_onchange = function (info) {
    if( lc_createClsCd.getValue() == scwin.MONPEROIDCREATE )
	{
        rd_std.setValue("1"); //rd_std[0].checked = true
        rd_std2.setValue("0"); //rd_std[1].checked = false
        $c.gus.cfDisableObjects([ed_stdDt]);
		$c.gus.cfEnableObjects([ed_stdYm]);
	}else if(lc_createClsCd.getValue() == scwin.DATEPERIODCREATE ){
		rd_std.setValue("0");
		rd_std2.setValue("1");
		$c.gus.cfEnableObjects([ed_stdDt]);
		$c.gus.cfDisableObjects([ed_stdYm]);
	}else if(lc_createClsCd.getValue() == scwin.MNGTACCTRECVCREATE )
	{
		rd_std.setValue("1");
		rd_std2.setValue("0");
		$c.gus.cfDisableObjects([ed_stdDt]);
		$c.gus.cfEnableObjects([ed_stdYm]);
	}else if(lc_createClsCd.getValue() == scwin.ACCTRECVOVERDAYCNTCREATE)
	{
		rd_std.setValue("0");
		rd_std2.setValue("1");
		$c.gus.cfEnableObjects([ed_stdDt]);
		$c.gus.cfDisableObjects([ed_stdYm]);
	}
};
//-------------------------------------------------------------------------
// 기준년월 라디오클릭 f_disableStdDt
//-------------------------------------------------------------------------
scwin.rd_std_onviewchange = function (info) {
    if (rd_std.getValue()=="1"){
        $c.gus.cfDisableObjects([ed_stdDt]);
        $c.gus.cfEnableObjects([ed_stdYm]);
        rd_std2.setValue("0");
    }
};
//-------------------------------------------------------------------------
// 기준일자 라디오클릭 f_disableStdDt
//-------------------------------------------------------------------------
scwin.rd_std2_onviewchange = function (info) {
    if (rd_std2.getValue()=="1"){
        $c.gus.cfDisableObjects([ed_stdYm]);
        $c.gus.cfEnableObjects([ed_stdDt]);
        rd_std.setValue("0");
    }
};

//-------------------------------------------------------------------------
// 월령생성
//-------------------------------------------------------------------------     
scwin.f_Create = async function (e) {
    let ret = "";
    let ret2 = "";
    let ret3 = "";
    let ret4 = "";

    ds_condition.removeAll();
    ds_condition.insertRow(0);

    if( lc_createClsCd.getValue() == scwin.DATEPERIODCREATE )
	{
		ret = await $c.gus.cfValidate([ed_stdYm]);
        if (!ret) {
			return false;
        }
	    ds_condition.setCellData(0, "stdCls", "1");//ds_condition.NameValue(1,"stdCls") = "1";
	}else if(lc_createClsCd.getValue() == scwin.MONPEROIDCREATE ){
		ret2 = await $c.gus.cfValidate([ed_stdDt]);
        if (!ret2) {
			return false;
        }
	   ds_condition.setCellData(0, "stdCls", "2");//ds_condition.NameValue(1,"stdCls") = "2";
	}else if(lc_createClsCd.getValue() == scwin.MNGTACCTRECVCREATE )
	{
		ret3 = await $c.gus.cfValidate([ed_stdYm]);
        if (!ret3) {
			return false;
        }
	    ds_condition.setCellData(0, "stdCls", "3");//ds_condition.NameValue(1,"stdCls") = "3";
	}else if(lc_createClsCd.getValue() == scwin.ACCTRECVOVERDAYCNTCREATE)
	{
		ret4 = await $c.gus.cfValidate([ed_stdDt]);
        if (!ret4) {
			return false;
        }
	    ds_condition.setCellData(0, "stdCls", "4");//ds_condition.NameValue(1,"stdCls") = "4";
	}

    ds_condition.setCellData(0, "coCd", ed_coCd.getValue());
    ds_condition.setCellData(0, "stdDt", ed_stdDt.getValue());
    ds_condition.setCellData(0, "stdYm", ed_stdYm.getValue());
    ds_condition.setCellData(0, "bilgAcctDept", ed_bilgAcctDept.getValue());

    if(await $c.win.confirm("월령을 생성하시겠습니까?")) {
        $c.sbm.execute(sbm_createAcctrecvperiod);
    }
};

//-------------------------------------------------------------------------
// 월령생성 콜백
//-------------------------------------------------------------------------     
scwin.sbm_createAcctrecvperiod_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    await $c.win.alert(MSG_CM_INF_001);
};    

//-------------------------------------------------------------------------
// 청구부서 코드입력시
//-------------------------------------------------------------------------    
scwin.udc_bilgAcctDept_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_bilgAcctDept, ed_txt_bilgAcctDeptNm,'1');
};

//-------------------------------------------------------------------------
// 청구부서찾기 버튼 클릭시
//-------------------------------------------------------------------------   
scwin.udc_bilgAcctDept_onclickEvent = function (info) {
    scwin.f_openPopUp('1',ed_bilgAcctDept,ed_txt_bilgAcctDeptNm);
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code) {
    try{

        if (orgObjNm.getValue() != orgObjNm.hidVal) {
            orgObjNm.setValue("");
        }

        if (orgObjCd.getValue().trim() != "") {
            scwin.f_openPopUp(select_code,orgObjCd,orgObjNm,"T");
        }else{
            if (orgObjNm == null) {
                orgObjNm.setValue("");
            }
            orgObjCd.setValue("");
            orgObjCd.hidVal = "";
        }

    } catch (e) {
       console.log("f_CheckPopUp : " + e);
    }
}; 

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->수금부서 , 2:조회->거래처
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (select_code,txtCode,txtName,sPopupCls) {
    try {

        let code = txtCode.getValue();
        let name = txtName.getValue();
        let param = "";
        switch (select_code) {
            // 관리부서 PopUp 호출
            case '1' :
                param    = ","+ ed_coCd.getValue()+","+scwin.txtCoClsCd;
                //rtnList = cfCommonPopUp(sCmdName,code,name,sPopupCls,null,null,null,null,param,null,null,null,null,null,"F",null,null); // 관리부서
                //udc_bilgAcctDept
                udc_bilgAcctDept.setSelectId('retrieveAcctDeptCdInfo6');
                udc_bilgAcctDept.cfCommonPopUp(scwin.udc_bilgAcctDept_callBackFunc // 콜백 함수
                        , code                            // 화면에서의  Code Element의 Value
                        , name                            // 화면에서의  Name Element의 Value
                        , sPopupCls                       // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , 'F'                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );
                break;
            // 거래처 PopUp 호출
  		    case '2' :
                //ASIS 미사용
                //sCmdName = "retrieveClntInfo"
			    //rtnList = cfCommonPopUp(sCmdName,code,name,sPopupCls,null,null,null,null,null,null,null,null,null); // 거래처
                break;
        }
    } catch (e) {
       console.log("f_openPopUp : " + e);
    }
}; 

//-------------------------------------------------------------------------
// 청구부서 PopUp 콜백
//-------------------------------------------------------------------------
scwin.udc_bilgAcctDept_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if (rtnList[0] == "N/A") return;
			ed_bilgAcctDept.setValue(rtnList[0]);	// 코드값
			ed_txt_bilgAcctDeptNm.setValue(rtnList[1]);	// 코드명
            ed_bilgAcctDept.hidVal = rtnList[0];	// HIDDEN 코드값
		} else {
			ed_bilgAcctDept.setValue("");
			ed_txt_bilgAcctDeptNm.setValue("");
            ed_bilgAcctDept.hidVal = "";
		}

    } catch (e) {
       console.log("udc_bilgAcctDept_callBackFunc " + e);
    }
};
